/*
 * Group per-minute anomaly rows by (router_ip, local_device_name)
 * and emit an alarm when high-anomaly or low-anomaly count crosses
 * the threshold inside the windowed batch.
 */
const HIGH_ALARM_THRESHOLD = 2;
const LOW_ALARM_THRESHOLD  = 2;

export const handler = async (input) => {
  const results = (input && input.anomaly_results) || [];
  const groups = {};
  for (const r of results) {
    const key = (r.router_ip || '') + '|' + (r.local_device_name || '');
    if (!groups[key]) {
      groups[key] = {
        router_ip: r.router_ip,
        local_device_name: r.local_device_name,
        high_count: 0,
        low_count: 0
      };
    }
    if (r.anomaly_flag === 'high_anomaly') groups[key].high_count += 1;
    else if (r.anomaly_flag === 'low_anomaly') groups[key].low_count += 1;
  }
  const now = new Date().toISOString();
  const alarms = [];
  for (const k of Object.keys(groups)) {
    const g = groups[k];
    if (g.high_count >= HIGH_ALARM_THRESHOLD || g.low_count >= LOW_ALARM_THRESHOLD) {
      alarms.push({
        created_at: now,
        router_ip: g.router_ip,
        local_device_name: g.local_device_name,
        high_count: g.high_count,
        low_count: g.low_count
      });
    }
  }
  return { alarms };
};
